        private void emitEvent(String eventName, JSONObject payload) {
            String safePayload = payload != null ? payload.toString() : "null";
            String js = "(function(){try{" +
                    "var ev;" +
                    "if(typeof CustomEvent==='function'){ev=new CustomEvent('" + escapeJs(eventName) + "',{detail:" + safePayload + "});}" +
                    "else{ev=document.createEvent('CustomEvent');ev.initCustomEvent('" + escapeJs(eventName) + "',true,true," + safePayload + ");}" +
                    "window.dispatchEvent(ev);" +
                    "}catch(e){console&&console.error&&console.error(e);}})();";
            webView.post(() -> webView.evaluateJavascript(js, null));
        }

        private void callback(String callbackId, JSONObject payload) {
            if (callbackId == null || callbackId.trim().isEmpty()) return;
            String safePayload = payload != null ? payload.toString() : "null";
            String js = "(function(){try{" +
                    "window.__nativeBridge=window.__nativeBridge||{};" +
                    "var cb=window.__nativeBridge['" + escapeJs(callbackId) + "'];" +
                    "if(typeof cb==='function'){cb(" + safePayload + "); delete window.__nativeBridge['" + escapeJs(callbackId) + "'];}" +
                    "}catch(e){console&&console.error&&console.error(e);}})();";
            webView.post(() -> webView.evaluateJavascript(js, null));
        }

