        private void launchCameraIntent(HybridWebViewActivity host, String callbackId) {
            Intent intent = new Intent(MediaStore.ACTION_IMAGE_CAPTURE);
            if (intent.resolveActivity(host.getPackageManager()) == null) {
                JSONObject o = new JSONObject();
                try {
                    o.put("ok", false);
                    o.put("error", "no_camera_app");
                } catch (JSONException ignored) {
                }
                callback(callbackId, o);
                return;
            }

            host.pendingActions.addLast(() -> {});

            ActivityResultLauncher<Intent> launcher = host.registerForActivityResult(
                    new ActivityResultContracts.StartActivityForResult(),
                    result -> {
                        JSONObject o = new JSONObject();
                        try {
                            if (result.getResultCode() == Activity.RESULT_OK) {
                                Intent data = result.getData();
                                Bitmap bmp = null;
                                if (data != null && data.getExtras() != null) {
                                    Object thumb = data.getExtras().get("data");
                                    if (thumb instanceof Bitmap) bmp = (Bitmap) thumb;
                                }
                                if (bmp != null) {
                                    ByteArrayOutputStream baos = new ByteArrayOutputStream();
                                    bmp.compress(Bitmap.CompressFormat.JPEG, 85, baos);
                                    String b64 = Base64.encodeToString(baos.toByteArray(), Base64.NO_WRAP);
                                    o.put("ok", true);
                                    o.put("imageBase64", "data:image/jpeg;base64," + b64);
                                } else {
                                    o.put("ok", true);
                                    o.put("imageBase64", JSONObject.NULL);
                                }
                            } else {
                                o.put("ok", false);
                                o.put("error", "cancelled");
                            }
                        } catch (JSONException ignored) {
                        }
                        callback(callbackId, o);
                    }
            );

            try {
                launcher.launch(intent);
            } catch (Throwable t) {
                JSONObject o = new JSONObject();
                try {
                    o.put("ok", false);
                    o.put("error", "launch_failed");
                    o.put("message", String.valueOf(t.getMessage()));
                } catch (JSONException ignored) {
                }
                callback(callbackId, o);
            }
        }

