    public static final class FileUtils {
        private FileUtils() {}

        public static java.io.File createTempImageFile(Context context) {
            java.io.File dir = context.getCacheDir();
            if (dir == null) dir = context.getFilesDir();
            String name = "capture_" + System.currentTimeMillis() + ".jpg";
            return new java.io.File(dir, name);
        }
    }

    public static final class LocationHelper {
        public interface LocationResult {
            void onSuccess(double lat, double lon, float accuracyMeters);
            void onError(String code, String message);
        }

        @SuppressLint("MissingPermission")
        public static void getLastKnownLocation(@NonNull Context context, @NonNull LocationResult cb) {
            try {
                android.location.LocationManager lm = (android.location.LocationManager) context.getSystemService(Context.LOCATION_SERVICE);
                if (lm == null) {
                    cb.onError("unavailable", "LocationManager unavailable");
                    return;
                }

                java.util.List<String> providers = lm.getProviders(true);
                android.location.Location best = null;
                for (String p : providers) {
                    android.location.Location l = lm.getLastKnownLocation(p);
                    if (l == null) continue;
                    if (best == null || l.getAccuracy() < best.getAccuracy()) best = l;
                }

                if (best != null) {
                    cb.onSuccess(best.getLatitude(), best.getLongitude(), best.getAccuracy());
                } else {
                    cb.onError("no_fix", "No last known location");
                }
            } catch (SecurityException se) {
                cb.onError("permission_denied", "Location permission denied");
            } catch (Throwable t) {
                cb.onError("error", String.valueOf(t.getMessage()));
            }
        }
    }
